#include <compare>
#include <iostream>
#include <string>

class Student
{
    int m_grade{};
    std::string m_name{};

public:
    Student() = default;
    Student(int grade, const std::string& name)
        : m_grade{ grade }, m_name{ name } {}

    auto operator<=>(const Student&) const = default;

    void print() const
    {
        std::cout << m_grade << ' ' << m_name << '\n';
    }
};

int main()
{
    Student students[3];
    for (int i{ 0 }; i < 3; ++i)
    {
        int g{};
        std::string n{};
        std::cin >> g >> n;
        students[i] = Student{ g, n };
    }

    for (int i{ 0 }; i < 2; ++i)
        for (int j{ i + 1 }; j < 3; ++j)
            if (students[j] < students[i])
            {
                Student temp{ students[i] };
                students[i] = students[j];
                students[j] = temp;
            }

    for (int i{ 0 }; i < 3; ++i)
        students[i].print();

    return 0;
}
